// MySpareParts Data Processing v1.0
const allItems = $input.all();
const currentDate = new Date();

const fmt = (n, d=2) => (n === null || n === undefined || isNaN(n)) ? 'N/A' : parseFloat(n).toFixed(d);
const pct = (c, p) => (!p || p === 0 || !c) ? null : ((c - p) / p * 100).toFixed(2);
const clean = (t) => t ? t.replace(/<[^>]*>/g, '').replace(/&[^;]+;/g, ' ').replace(/\s+/g, ' ').trim().slice(0, 300) : '';

const heroImages = {
  competitors: "https://images.unsplash.com/photo-1553877522-43269d4ea984?auto=format&fit=crop&w=800&q=80",
  industry: "https://images.unsplash.com/photo-1581092160562-40aa08e78837?auto=format&fit=crop&w=800&q=80",
  technology: "https://images.unsplash.com/photo-1485827404703-89b55fcc595e?auto=format&fit=crop&w=800&q=80",
  regulatory: "https://images.unsplash.com/photo-1589829545856-d10d557cf95f?auto=format&fit=crop&w=800&q=80",
  funding: "https://images.unsplash.com/photo-1559526324-4b87b5e36e44?auto=format&fit=crop&w=800&q=80",
  agri: "https://images.unsplash.com/photo-1625246333195-58197bd47d19?auto=format&fit=crop&w=800&q=80",
  construction: "https://images.unsplash.com/photo-1504307651254-35680f356dfd?auto=format&fit=crop&w=800&q=80",
  supplychain: "https://images.unsplash.com/photo-1586528116311-ad8dd3c8310d?auto=format&fit=crop&w=800&q=80"
};

const data = {
  reportDate: currentDate.toLocaleDateString('en-US', { 
    weekday: 'long', year: 'numeric', month: 'long', day: 'numeric', 
    hour: '2-digit', minute: '2-digit', timeZone: 'Europe/Amsterdam' 
  }),
  stocks: {},
  forex: {},
  news: {
    competitors: [],
    industry: [],
    agriParts: [],
    constructionParts: [],
    municipal: [],
    technology: [],
    regulatory: [],
    funding: [],
    oem: [],
    distributors: [],
    supplyChain: [],
    marketplaces: []
  },
  summaries: {},
  images: heroImages
};

const competitors = ['partao', 'sparetech', 'partium', 'synthavo', 'ovoko', 'tvh'];

allItems.forEach(item => {
  const j = item.json;

  // Stock data
  if (j?.chart?.result?.[0]) {
    const c = j.chart.result[0];
    const m = c.meta;
    const q = c.indicators?.quote?.[0];

    if (m && q) {
      const i = (q.close?.length || 1) - 1;
      const price = q.close?.[i] || m.regularMarketPrice;
      const prev = m.chartPreviousClose || m.previousClose || q.close?.[i-1];
      const chg = price && prev ? price - prev : null;
      const chgPct = pct(price, prev);
      const s = m.symbol || '';

      const mk = {
        price: fmt(price), 
        change: chg !== null ? fmt(chg) : 'N/A',
        changePercent: chgPct ? chgPct + '%' : 'N/A',
        isPositive: chg > 0, 
        isNegative: chg < 0
      };

      if (s === 'X') data.stocks.steel = { ...mk, name: 'US Steel' };
      else if (s === 'DE') data.stocks.deere = { ...mk, name: 'John Deere' };
      else if (s === 'CAT') data.stocks.cat = { ...mk, name: 'Caterpillar' };
      else if (s === 'CNHI') data.stocks.cnh = { ...mk, name: 'CNH Industrial' };
      else if (s === 'AGCO') data.stocks.agco = { ...mk, name: 'AGCO' };
    }
  }

  // Forex
  if (j?.rates && j?.base === 'USD') {
    data.forex = {
      EUR: fmt(j.rates.EUR, 4),
      GBP: fmt(j.rates.GBP, 4),
      CHF: fmt(j.rates.CHF, 4),
      SEK: fmt(j.rates.SEK, 4),
      PLN: fmt(j.rates.PLN, 4)
    };
  }

  // News
  if (j?.title && (j?.link || j?.url)) {
    const rawSummary = j.summary || j.description || j.contentSnippet || j.content || '';
    const summary = clean(rawSummary);
    const news = { 
      title: j.title?.slice(0, 150), 
      link: j.link || j.url, 
      source: j.source || j.creator || '', 
      pubDate: j.pubDate || j.isoDate || '',
      summary: summary
    };
    const txt = ((j.title || '') + ' ' + (j.link || '') + ' ' + summary).toLowerCase();

    // Competitor detection (EXPLICIT)
    if (competitors.some(c => txt.includes(c))) {
      data.news.competitors.push(news);
    }

    // Categories
    if (txt.match(/agricultur|tractor|farm|harvest|agri/)) {
      data.news.agriParts.push(news);
    }
    if (txt.match(/construct|excavat|bulldoz|crane|heavy.equip/)) {
      data.news.constructionParts.push(news);
    }
    if (txt.match(/municipal|fleet|truck|vehicle|sanitation/)) {
      data.news.municipal.push(news);
    }
    if (txt.match(/ai|artificial|visual.search|machine.learn|automation/)) {
      data.news.technology.push(news);
    }
    if (txt.match(/regulat|right.to.repair|directive|compliance|eu.law/)) {
      data.news.regulatory.push(news);
    }
    if (txt.match(/funding|invest|series.[a-c]|seed|acquisition|merger/i)) {
      data.news.funding.push(news);
    }
    if (txt.match(/deere|caterpillar|cnh|agco|kubota|liebherr|komatsu/)) {
      data.news.oem.push(news);
    }
    if (txt.match(/tvh|kramp|distributor|wholesale/)) {
      data.news.distributors.push(news);
    }
    if (txt.match(/supply.chain|logistics|shortage|disruption/)) {
      data.news.supplyChain.push(news);
    }
    if (txt.match(/mascus|ironplanet|ritchie|marketplace/)) {
      data.news.marketplaces.push(news);
    }
    if (txt.match(/spare.part|aftermarket|replacement|oem.part/)) {
      data.news.industry.push(news);
    }
  }

  // Perplexity
  if (j?.choices?.[0]?.message?.content) {
    data.summaries.perplexity = j.choices[0].message.content;
  }
});

const sortLimit = (arr, n) => arr
  .filter(x => x.title)
  .sort((a, b) => new Date(b.pubDate || 0) - new Date(a.pubDate || 0))
  .slice(0, n);

data.news.competitors = sortLimit(data.news.competitors, 10);
data.news.industry = sortLimit(data.news.industry, 8);
data.news.agriParts = sortLimit(data.news.agriParts, 6);
data.news.constructionParts = sortLimit(data.news.constructionParts, 6);
data.news.municipal = sortLimit(data.news.municipal, 5);
data.news.technology = sortLimit(data.news.technology, 6);
data.news.regulatory = sortLimit(data.news.regulatory, 5);
data.news.funding = sortLimit(data.news.funding, 6);
data.news.oem = sortLimit(data.news.oem, 6);
data.news.distributors = sortLimit(data.news.distributors, 5);
data.news.supplyChain = sortLimit(data.news.supplyChain, 5);
data.news.marketplaces = sortLimit(data.news.marketplaces, 5);

return [{ json: data }];

// MySpareParts HTML Report v1.0
let data = {};
try {
  data = $input.first().json;
} catch (e) {
  data = {};
}

const reportDate = data.reportDate || new Date().toLocaleDateString('en-US', { weekday:'long', year:'numeric', month:'long', day:'numeric' });
const imgs = data.images || {};
const stocks = data.stocks || {};
const forex = data.forex || {};
const news = data.news || {};
const summaries = data.summaries || {};

function sectionHeader(title, imageUrl, emoji) {
  return `<div style="width: 100%; background-color: #f0f0f0;"><img src="${imageUrl}" alt="${title}" width="600" style="width: 100%; max-width: 100%; height: auto; max-height: 120px; object-fit: cover; display: block; border: 0;" /></div><div style="background-color: #393E46; padding: 12px 20px; border-bottom: 4px solid #F36E21;"><h2 style="margin: 0; color: #ffffff; font-family: 'Helvetica Neue', Helvetica, Arial, sans-serif; font-size: 16px; text-transform: uppercase; letter-spacing: 1px; line-height: 1.2;">${emoji} ${title}</h2></div>`;
}

function newsHtml(items, msg) {
  if (!items || !Array.isArray(items) || items.length === 0) {
    return `<div style="padding: 15px 20px;"><p style="margin:0; color:#6c757d; font-style:italic; font-size: 13px;">${msg}</p></div>`;
  }
  const listItems = items.map(n => `<li style="padding: 10px 0; border-bottom: 1px solid #f0f0f0;"><a href="${n.link || '#'}" style="color:#F36E21; text-decoration:none; font-weight:700; font-size:14px; line-height:1.4; display:block;" target="_blank">${n.title || 'News'}</a><div style="margin-top:4px;"><span style="font-size:10px; color:#666; background:#e9ecef; padding:2px 6px; border-radius:4px; text-transform:uppercase;">${n.source || 'Source'}</span></div></li>`).join('');
  return `<ul style="list-style:none; padding: 5px 20px 15px; margin:0;">${listItems}</ul>`;
}

function renderSection(title, imageKey, newsArray, defaultMsg, emoji) {
  const imageUrl = imgs[imageKey] || imgs.industry || 'https://images.unsplash.com/photo-1581092160562-40aa08e78837?auto=format&fit=crop&w=800&q=80';
  return `<div style="margin-bottom: 30px; border: 1px solid #e0e0e0; border-radius: 8px; overflow: hidden; background-color: #ffffff;">${sectionHeader(title, imageUrl, emoji)}${newsHtml(newsArray, defaultMsg)}</div>`;
}

const valColor = (val, pos) => {
  if (val === undefined || val === null || val === 'N/A') return '<span style="color:#6c757d;">N/A</span>';
  const c = pos === true ? '#28a745' : pos === false ? '#dc3545' : '#333';
  const a = pos === true ? '▲' : pos === false ? '▼' : '';
  return `<span style="color:${c};font-weight:700;">${a} ${val}</span>`;
};

const weekNum = Math.ceil((new Date() - new Date(new Date().getFullYear(), 0, 1)) / 604800000);

let html = `<!DOCTYPE html><html><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1.0"></head><body style="margin:0;padding:0;font-family:'Helvetica Neue', Helvetica, Arial, sans-serif;background-color:#f4f4f4;color:#333;">
<div style="max-width:600px;margin:20px auto;background-color:#ffffff;border-radius:0px;overflow:hidden;">

<!-- Header -->
<div style="background-color:#393E46;padding:30px 20px;text-align:center;">
  <div style="color:#F36E21;font-size:10px;letter-spacing:3px;font-weight:700;margin-bottom:8px;text-transform:uppercase;">B2B Spare Parts Intelligence</div>
  <h1 style="color:#ffffff;margin:0;font-size:26px;font-weight:800;letter-spacing:-0.5px;">MySpareParts</h1>
  <p style="color:#F36E21;margin:5px 0 0;font-size:16px;font-weight:600;">Weekly Intelligence Brief</p>
  <p style="color:#9ca3af;margin:10px 0 0;font-size:12px;">Week ${weekNum} | ${reportDate}</p>
</div>

<!-- Tagline -->
<div style="background-color:#F36E21;padding:10px;text-align:center;color:#ffffff;font-weight:600;font-size:13px;">Your competitive edge in the B2B spare parts market</div>

<div style="padding:20px;">

<!-- OEM Stocks -->
<div style="margin-bottom:25px;background-color:#f8f9fa;padding:15px;border-radius:8px;border:1px solid #e0e0e0;">
  <h3 style="margin:0 0 12px;font-size:12px;text-transform:uppercase;letter-spacing:1px;color:#393E46;font-weight:700;">OEM Stock Watch</h3>
  <table width="100%" cellspacing="0" cellpadding="0" border="0" style="font-size:12px;">
    <tr style="background-color:#393E46;color:#fff;"><th style="padding:6px 8px;text-align:left;">Company</th><th style="padding:6px 8px;text-align:right;">Price</th><th style="padding:6px 8px;text-align:right;">Change</th></tr>
    <tr><td style="padding:6px 8px;border-bottom:1px solid #eee;">John Deere (DE)</td><td style="text-align:right;padding:6px 8px;border-bottom:1px solid #eee;">${stocks.deere?.price || '-'}</td><td style="text-align:right;padding:6px 8px;border-bottom:1px solid #eee;">${valColor(stocks.deere?.changePercent, stocks.deere?.isPositive)}</td></tr>
    <tr><td style="padding:6px 8px;border-bottom:1px solid #eee;">Caterpillar (CAT)</td><td style="text-align:right;padding:6px 8px;border-bottom:1px solid #eee;">${stocks.cat?.price || '-'}</td><td style="text-align:right;padding:6px 8px;border-bottom:1px solid #eee;">${valColor(stocks.cat?.changePercent, stocks.cat?.isPositive)}</td></tr>
    <tr><td style="padding:6px 8px;border-bottom:1px solid #eee;">CNH Industrial</td><td style="text-align:right;padding:6px 8px;border-bottom:1px solid #eee;">${stocks.cnh?.price || '-'}</td><td style="text-align:right;padding:6px 8px;border-bottom:1px solid #eee;">${valColor(stocks.cnh?.changePercent, stocks.cnh?.isPositive)}</td></tr>
    <tr><td style="padding:6px 8px;border-bottom:1px solid #eee;">AGCO</td><td style="text-align:right;padding:6px 8px;border-bottom:1px solid #eee;">${stocks.agco?.price || '-'}</td><td style="text-align:right;padding:6px 8px;border-bottom:1px solid #eee;">${valColor(stocks.agco?.changePercent, stocks.agco?.isPositive)}</td></tr>
    <tr><td style="padding:6px 8px;">US Steel (X)</td><td style="text-align:right;padding:6px 8px;">${stocks.steel?.price || '-'}</td><td style="text-align:right;padding:6px 8px;">${valColor(stocks.steel?.changePercent, stocks.steel?.isPositive)}</td></tr>
  </table>
</div>

<!-- AI Summary -->
${summaries.perplexity ? `<div style="margin-bottom:25px;background-color:#fff3cd;padding:15px;border-left:4px solid #F36E21;color:#333;border-radius:0 8px 8px 0;">
  <h3 style="margin:0 0 10px;font-size:11px;text-transform:uppercase;letter-spacing:1px;color:#F36E21;font-weight:700;">AI Intelligence Summary</h3>
  <p style="margin:0;font-size:13px;line-height:1.6;">${summaries.perplexity.slice(0, 800)}${summaries.perplexity.length > 800 ? '...' : ''}</p>
</div>` : ''}

<!-- Sections -->
${renderSection('Competitor Watch', 'competitors', news.competitors, 'No competitor news this week.', '🎯')}
${renderSection('Industry News', 'industry', news.industry, 'No industry news.', '📰')}
${renderSection('Agricultural Parts', 'agri', news.agriParts, 'No agricultural news.', '🚜')}
${renderSection('Construction Parts', 'construction', news.constructionParts, 'No construction news.', '🏗️')}
${renderSection('Technology & AI', 'technology', news.technology, 'No tech news.', '🤖')}
${renderSection('Funding & Deals', 'funding', news.funding, 'No funding news.', '💰')}
${renderSection('EU Regulatory', 'regulatory', news.regulatory, 'No regulatory news.', '⚖️')}
${renderSection('OEM Updates', 'industry', news.oem, 'No OEM news.', '🏭')}
${renderSection('Supply Chain', 'supplychain', news.supplyChain, 'No supply chain news.', '📦')}

</div>

<!-- Footer -->
<div style="background-color:#393E46;padding:20px;text-align:center;border-top:4px solid #F36E21;font-size:11px;color:#888;">
  <p style="margin:0;">MySpareParts Weekly Intelligence Brief</p>
  <p style="margin:5px 0 0;color:#F36E21;">Powered by N8N + Perplexity AI</p>
</div>

</div></body></html>`;

const dateShort = new Date().toLocaleDateString('en-US', { day:'numeric', month:'short' });

return [{ json: { subject: `MySpareParts Intel Brief - Week ${weekNum} | ${dateShort}`, htmlContent: html, reportDate } }];
